+
+    // Phase 2: spike
+    for _ in 0..10 {
+        cascade.post_render(25_000.0, key);
+        cascade.pre_render(BUDGET_US, key);
+        if let Some(evidence) = cascade.last_evidence() {
+            evidence_log.push(evidence.to_jsonl());
+        }
+    }
+
+    // Phase 3: recovery
+    for _ in 0..20 {
+        cascade.post_render(8_000.0, key);
+        cascade.pre_render(BUDGET_US, key);
